-- 0008_marketing_persona_sections.sql
-- Ficha completa de cada avatar (buyer persona extenso: 6 a 10 secciones con
-- bloques de texto, cita, lista, tabla o comparativa de 2-3 columnas), separada
-- del resumen corto ya existente (headline/description). Contenido de solo
-- lectura frecuente; se transcribio y verifico contra los documentos fuente
-- (Ficha_Avatar_*.docx) con fidelidad 1:1 antes de sembrarla aqui.
-- Idempotente: se puede correr mas de una vez sin dano.

alter table public.marketing_avatars
  add column if not exists persona_sections jsonb;

update public.marketing_avatars
  set persona_sections = '{"role_title":"El Profesional Integrador","tagline":"Audiencia principal de YouTube · Comprador potencial del bootcamp","channel":"YouTube","priority_offer":"Bootcamp","strategic_role":"Profesional integrador","sections":[{"title":"Identidad, contexto y momento profesional","blocks":[{"type":"text","label":"Identidad funcional","body":"Mateo o Mariana es un profesional con responsabilidad creciente que necesita integrar pensamiento estratégico, crítico, analítico, creativo y técnico para seguir siendo relevante y producir mejores resultados en su trabajo. No quiere limitarse a aprender herramientas de inteligencia artificial. Quiere comprender cuándo utilizarlas, para qué sirven, cómo relacionarlas con un problema real y cómo liderar su aplicación dentro de un equipo o proyecto."},{"type":"grid","columns":[{"label":"Perfil profesional","body":"Habitualmente ocupa posiciones como:","items":["Coordinador o líder de proyecto.","Profesional especializado.","Consultor sénior.","Jefe de área.","Líder de innovación, comunicaciones, conocimiento o transformación.","Gestor de proyectos culturales o turísticos.","Profesional del sector público.","Emprendedor con un equipo pequeño.","Persona que conecta áreas técnicas, administrativas y creativas."]},{"label":"Sectores y rasgo común","body":"Puede trabajar en empresas, instituciones públicas, universidades, organizaciones culturales, turismo, educación, comunicaciones, consultoría o servicios profesionales. Su característica común no es el sector. Es que su trabajo exige interpretar problemas, coordinar personas, presentar soluciones y tomar decisiones con información incompleta."}]},{"type":"list","label":"Momento profesional","body":"Mateo o Mariana ya tiene experiencia. No está empezando su carrera, pero percibe que las reglas del trabajo están cambiando. Ha probado ChatGPT, Claude, Gemini, herramientas de automatización o asistentes digitales. Puede utilizarlas para redactar, resumir o generar ideas, pero siente que su uso todavía es fragmentado y superficial. Empieza a observar que:","items":["Algunos compañeros producen más utilizando IA.","La organización comienza a exigir propuestas de innovación.","Aparecen nuevas herramientas constantemente.","Los equipos técnicos hablan en un lenguaje que no siempre comprende.","Su experiencia sigue siendo valiosa, pero necesita combinarla con nuevas capacidades.","Aprender herramientas aisladas no le permite transformar realmente su trabajo."]},{"type":"quote","label":"Tensión principal","body":"\"No quiero quedarme atrás, pero tampoco quiero convertirme en alguien que usa herramientas sin criterio.\" Esta tensión es central para Divergente. Mateo y Mariana quieren avanzar tecnológicamente sin abandonar su experiencia, pensamiento propio ni capacidad de análisis."}]},{"title":"Trabajo por resolver y capacidades necesarias","blocks":[{"type":"text","label":"Trabajo que necesita resolver","body":"Integrar inteligencia artificial, tecnología y datos en su trabajo para diseñar mejores soluciones, aumentar su capacidad profesional y liderar proyectos con mayor criterio."},{"type":"table","headers":["Capacidad","Lo que necesita lograr"],"rows":[["Pensamiento estratégico","Identificar dónde tiene sentido intervenir y qué resultados priorizar."],["Pensamiento crítico","Evaluar promesas, riesgos, límites y resultados de las herramientas."],["Pensamiento analítico","Comprender datos, procesos, patrones y evidencia."],["Pensamiento creativo","Diseñar alternativas y soluciones no convencionales."],["Capacidad técnica aplicada","Utilizar herramientas, automatizaciones y modelos de IA en situaciones reales."]]},{"type":"text","label":"Problema principal","body":"Mateo o Mariana encuentra mucha información sobre herramientas, pero poca formación que conecte tecnología, problemas reales, estrategia y pensamiento. Consume tutoriales, cursos y contenidos, pero termina con conocimientos dispersos que no siempre sabe convertir en resultados."},{"type":"list","label":"Problemas secundarios","body":"Vive además una sobrecarga de información: cada semana aparecen nuevas herramientas, y sin un criterio claro para priorizar, salta de un tutorial a otro sin construir una base sólida ni un método propio. Aprende de forma autodidacta, sin acompañamiento que traduzca lo que consume en aplicaciones concretas para su contexto laboral, por lo que su curva de aprendizaje es lenta y depende del ensayo y error. Usa la IA para tareas puntuales, pero no ha dado el salto de usuario táctico a líder de soluciones: sabe operar herramientas, pero le falta el criterio para rediseñar procesos y liderar proyectos de transformación con ellas.","items":["No sabe qué herramientas vale la pena aprender.","Siente que cada semana aparece una nueva plataforma.","Le cuesta pasar del experimento personal a una aplicación profesional.","No tiene tiempo para formaciones excesivamente largas.","No quiere aprender programación desde cero.","Tiene dificultades para explicar una solución tecnológica a sus superiores.","No sabe cómo medir si una implementación realmente funciona.","Puede identificar problemas, pero no siempre sabe traducirlos en procesos o soluciones.","Utiliza IA para tareas pequeñas, pero no para rediseñar su manera de trabajar.","Le preocupa depender demasiado de herramientas sin comprenderlas."]}]},{"title":"Transformación, motivaciones y barreras","blocks":[{"type":"list","label":"Resultado deseado","body":"Mateo o Mariana quiere convertirse en una persona capaz de:","items":["Identificar oportunidades de aplicación.","Formular mejores problemas.","Diseñar soluciones.","Probar herramientas rápidamente.","Dialogar con perfiles técnicos.","Liderar proyectos interdisciplinarios.","Tomar decisiones con datos.","Explicar la tecnología de forma sencilla.","Construir sistemas de trabajo propios.","Aumentar su valor dentro de la organización."]},{"type":"text","label":"Transformación buscada","body":"No busca convertirse en ingeniero de inteligencia artificial. Busca convertirse en un profesional aumentado por tecnología y fortalecido por criterio."},{"type":"grid","columns":[{"label":"Motivaciones profundas","body":"Su motivación visible es aprender IA. Su motivación profunda puede ser:","items":["Mantener su relevancia profesional.","Ganar autonomía.","Obtener reconocimiento dentro de la organización.","Acceder a cargos de mayor responsabilidad.","Liderar proyectos más importantes.","Sentirse preparado frente al cambio.","Evitar depender completamente de equipos técnicos.","Convertir sus ideas en soluciones ejecutables.","Demostrar que puede conectar estrategia y ejecución."]},{"label":"Miedos","items":["Quedarse profesionalmente desactualizado.","Ser reemplazado o desplazado.","Parecer poco competente frente a colegas más jóvenes o técnicos.","Comprar cursos que repiten información superficial.","Invertir tiempo en herramientas que pronto desaparezcan.","Proponer una solución que no funcione.","Exponer información sensible en herramientas de IA.","No poder trasladar lo aprendido a su contexto laboral.","Terminar acumulando certificados sin capacidades reales."]}]},{"type":"list","label":"Objeciones frente al bootcamp","items":["\"No sé si esto será demasiado técnico para mí.\"","\"Ya he tomado cursos de IA y todos enseñan lo mismo.\"","\"No tengo tiempo para una formación extensa.\"","\"Mi sector es muy particular; quizá los ejemplos no me sirvan.\"","\"¿Realmente voy a construir algo aplicable?\"","\"Puedo encontrar tutoriales gratuitos en YouTube.\""]},{"type":"text","label":"Respuesta de Divergente","body":"La respuesta de Divergente no debería centrarse únicamente en la cantidad de herramientas. Debe demostrar que el bootcamp ofrece método, aplicación, criterio, acompañamiento y construcción de soluciones reales."}]},{"title":"Comportamiento en YouTube y consumo de contenido","blocks":[{"type":"text","label":"Comportamiento en YouTube","body":"Mateo o Mariana entra a YouTube buscando resolver una situación concreta."},{"type":"grid","columns":[{"label":"Búsquedas posibles","items":["Cómo aplicar IA en mi trabajo.","Herramientas de IA para profesionales.","Cómo automatizar un proceso.","Cómo crear un agente de IA.","Cómo usar ChatGPT con datos.","IA para líderes de proyecto.","Cómo mejorar la productividad de un equipo.","Cómo rediseñar procesos antes de automatizarlos.","Habilidades profesionales del futuro.","Qué necesito aprender sobre inteligencia artificial."]},{"label":"Qué valora en los contenidos","items":["Explican rápidamente por qué algo importa.","Utilizan ejemplos profesionales.","Evitan tecnicismos innecesarios.","Comparan opciones.","Muestran procesos completos.","Presentan una postura crítica.","Incluyen casos reales.","Le entregan una metodología que pueda replicar."]}]},{"type":"list","label":"Contenidos que pueden atraerlo","items":["\"No necesitas aprender todas las herramientas de IA.\"","\"Las cinco capacidades que necesita un profesional en la era de la IA.\"","\"Cómo pasar de usar ChatGPT a diseñar soluciones.\"","\"No automatices un proceso que todavía funciona mal.\"","\"Qué debe saber de IA un coordinador de proyectos.\"","\"Cómo trabajar con un equipo técnico sin ser programador.\"","\"La IA no te reemplaza: cambia el valor de tu experiencia.\"","\"Cómo identificar procesos que sí vale la pena automatizar.\"","\"De usuario de herramientas a líder de soluciones.\"","\"Por qué aprender prompts no es suficiente.\""]}]},{"title":"Compra, conversión y relación con Divergente","blocks":[{"type":"list","label":"Detonantes de compra","items":["Recibe una nueva responsabilidad.","Debe liderar un proyecto de innovación.","Su jefe solicita una propuesta relacionada con IA.","Ve que otros profesionales avanzan más rápido.","Tiene que coordinar un proveedor tecnológico.","Se anuncia una transformación dentro de la organización.","Su contrato o posición laboral se vuelve incierta.","Necesita mostrar resultados en poco tiempo.","Encuentra un caso de Divergente parecido a su realidad.","Comprende que el bootcamp produce una solución, no solo conocimiento."]},{"type":"table","headers":["Etapa","Qué ocurre"],"rows":[["Descubrimiento","Encuentra un video sobre un problema profesional."],["Reconocimiento","Comprende que no necesita únicamente herramientas, sino desarrollar nuevas capacidades."],["Confianza","Consume metodologías, casos, análisis y demostraciones de Divergente."],["Evaluación","Revisa el programa del bootcamp, resultados, duración y aplicabilidad."],["Compra","Se inscribe porque encuentra una ruta estructurada y compatible con su perfil no exclusivamente técnico."],["Continuidad","Ingresa a Skool para seguir aprendiendo, recibe acompañamiento o recomienda la formación dentro de su empresa."]]},{"type":"quote","label":"Promesa para Mateo y Mariana","body":"Aprende a pensar, diseñar y aplicar soluciones con inteligencia artificial, datos y tecnología, sin reducir tu desarrollo profesional a aprender herramientas aisladas."}]},{"title":"Límites del perfil e hipótesis por validar","blocks":[{"type":"text","label":"Lo que no es este avatar","body":"No es una persona que solo busca trucos rápidos, coleccionar prompts o generar contenido automáticamente. Tampoco es un perfil completamente técnico interesado principalmente en programación, arquitectura de modelos o ingeniería avanzada. Su valor está en conectar conocimiento, contexto, personas y tecnología."},{"type":"list","label":"Hipótesis que tendremos que validar","items":["Que ocupa principalmente cargos medios y medio-altos.","Que su miedo principal es perder relevancia profesional.","Que valora más la aplicación que la certificación.","Que YouTube es su principal canal de aprendizaje.","Que puede pagar directamente el bootcamp o conseguir que su organización lo financie.","Que el concepto de \"profesional integrador\" resulta reconocible.","Que las cinco capacidades propuestas reflejan lo que realmente necesita."]},{"type":"text","label":"Decisión pendiente para aterrizar el perfil","body":"Seleccionar los tres sectores o tipos de organización que deberían aparecer primero en sus ejemplos: sector público, empresas privadas, industrias culturales, turismo, educación, comunicaciones, consultoría u otros."}]}]}'::jsonb
  where slug = 'mateo';

update public.marketing_avatars
  set persona_sections = '{"role_title":"El Decisor de Transformación","tagline":"Tomador de decisión · Audiencia B2B · LinkedIn, CRM, casos y autoridad de YouTube","channel":"LinkedIn · CRM · casos · autoridad","priority_offer":"B2B y formación empresarial","strategic_role":"Decisor de transformación","sections":[{"title":"Identidad, contexto y momento directivo","blocks":[{"type":"text","label":"Identidad funcional","body":"Jaime o Diana es un alto directivo con responsabilidad sobre resultados, presupuesto, personas y reputación institucional. Necesita comprender la inteligencia artificial, los datos y la tecnología lo suficiente para tomar decisiones, orientar a sus equipos, evaluar proveedores y controlar riesgos, sin convertirse en operador técnico. No busca aprender cada herramienta. Quiere saber qué debe priorizar, qué puede delegar, qué preguntas hacer y cómo convertir la transformación tecnológica en una capacidad real de la organización."},{"type":"grid","columns":[{"label":"Perfil profesional","body":"Habitualmente ocupa posiciones como:","items":["CEO, fundador, socio o gerente general.","Director ejecutivo o vicepresidente.","Director de área, jefe de oficina o líder institucional.","Responsable de innovación o transformación digital.","Alto directivo del sector público.","Líder de una asociación, universidad u organización sectorial.","Persona que autoriza presupuesto, define prioridades y responde por resultados."]},{"label":"Sectores y rasgo común","body":"Puede trabajar en empresas medianas o grandes, entidades públicas, universidades, organizaciones culturales, turismo, educación, servicios profesionales, gremios o industrias intensivas en conocimiento. Su característica común no es el sector. Es que tiene autoridad sobre recursos y personas, debe rendir cuentas y necesita alinear estrategia, operación, tecnología y cambio organizacional."}]},{"type":"list","label":"Momento directivo","body":"Jaime o Diana observa que la inteligencia artificial ya está entrando a la organización, pero de forma desigual y poco coordinada. Algunas áreas hacen experimentos, otras solicitan herramientas y los proveedores presentan soluciones difíciles de comparar. Empieza a observar que:","items":["Los equipos adoptan herramientas sin criterios compartidos.","La junta, la dirección o el mercado exige una hoja de ruta de IA.","Las propuestas técnicas no siempre se traducen en resultados de negocio.","Existen dudas sobre datos, seguridad, propiedad intelectual y reputación.","Se acumulan pilotos que no escalan ni se integran a los procesos.","La organización necesita formar equipos, no solo comprar licencias."]},{"type":"quote","label":"Tensión principal","body":"\"Necesito liderar esta transformación, pero no tengo tiempo para convertirme en especialista técnico ni margen para cometer errores costosos.\" Esta tensión es central para Divergente. Jaime y Diana quieren comprender lo suficiente para dirigir con criterio, sin perderse en la operación técnica ni delegar ciegamente decisiones estratégicas."}]},{"title":"Trabajo por resolver y capacidades directivas","blocks":[{"type":"text","label":"Trabajo que necesita resolver","body":"Dirigir la adopción de inteligencia artificial, datos, automatización y tecnología, alineando personas, procesos y decisiones para generar valor medible, controlar riesgos y construir capacidades internas sostenibles."},{"type":"table","headers":["Capacidad directiva","Lo que necesita lograr"],"rows":[["Priorización estratégica","Distinguir oportunidades relevantes de modas, urgencias y proyectos de bajo impacto."],["Traducción negocio-tecnología","Convertir necesidades organizacionales en preguntas, criterios y alcances comprensibles para equipos técnicos."],["Liderazgo de equipos y cambio","Alinear roles, expectativas, formación y adopción entre áreas con niveles distintos de madurez."],["Gobernanza y gestión del riesgo","Definir criterios sobre datos, seguridad, propiedad intelectual, ética, reputación y uso responsable."],["Evaluación de inversión y valor","Comparar propuestas, decidir entre comprar, desarrollar o automatizar y medir resultados más allá del ahorro de tiempo."]]},{"type":"text","label":"Problema principal","body":"El problema de Jaime o Diana no es la falta de herramientas, sino la ausencia de una hoja de ruta clara para decidir qué adoptar, cómo gobernarlo, quién debe liderarlo y qué resultados debe producir. Recibe información fragmentada de equipos, consultores, proveedores y medios, pero necesita convertirla en decisiones ejecutivas coherentes."},{"type":"list","label":"Problemas secundarios","items":["Tiene muy poco tiempo para estudiar contenidos técnicos extensos.","Recibe promesas difíciles de contrastar por parte de proveedores.","Existen pilotos aislados que no escalan ni comparten aprendizajes.","Las áreas técnicas y de negocio no siempre utilizan el mismo lenguaje.","No están claros los roles, responsabilidades ni límites de uso de la IA.","Le preocupan la seguridad, los datos, la propiedad intelectual y la reputación.","Se intentan automatizar procesos deficientes sin rediseñarlos primero.","Existe presión por mostrar resultados rápidos sin una base sólida.","No sabe cómo calcular retorno, impacto o costo total de una implementación.","Puede depender demasiado de proveedores o personas técnicas clave.","Debe formar equipos con niveles de conocimiento y resistencia diferentes.","Teme que la transformación genere fatiga, desconfianza o inequidad interna."]}]},{"title":"Transformación, motivaciones y barreras","blocks":[{"type":"list","label":"Resultado deseado","body":"Jaime o Diana quiere convertirse en una persona capaz de:","items":["Comprender las posibilidades estratégicas de la IA sin dominar cada herramienta.","Definir una hoja de ruta realista y priorizada.","Hacer mejores preguntas a equipos y proveedores.","Decidir qué comprar, desarrollar, automatizar o descartar.","Alinear a líderes, áreas técnicas y equipos operativos.","Evaluar propuestas desde el valor, el riesgo y la viabilidad.","Patrocinar iniciativas con objetivos, responsables y métricas claras.","Establecer principios de gobernanza y uso responsable.","Comunicar decisiones a la junta, a la dirección y a los equipos.","Convertir pilotos dispersos en capacidades organizacionales."]},{"type":"text","label":"Transformación buscada","body":"No busca convertirse en especialista técnico. Busca pasar de reaccionar con incertidumbre frente a la IA a dirigir una transformación con criterio, prioridades, responsables, protección institucional y resultados medibles."},{"type":"grid","columns":[{"label":"Motivaciones profundas","body":"Su motivación visible es modernizar la organización. Sus motivaciones profundas pueden ser:","items":["Sostener la competitividad y la capacidad de respuesta.","Mejorar productividad, servicio y toma de decisiones.","Reducir fricciones y dependencia de procesos manuales.","Proteger la organización frente a riesgos evitables.","Fortalecer su reputación como líder preparado.","Retener talento y ofrecer mejores condiciones de trabajo.","Dejar capacidades instaladas, no proyectos pasajeros.","Demostrar que innovación y resultados pueden avanzar juntos."]},{"label":"Miedos","items":["Autorizar una inversión que no produzca resultados.","Sufrir un incidente jurídico, reputacional o de seguridad.","Perder control sobre decisiones que no comprende.","Quedar rezagado frente a competidores u otras instituciones.","Generar resistencia o ansiedad dentro del equipo.","Depender de un proveedor o solución cerrada.","Exponer información sensible en herramientas externas.","Acumular pilotos, licencias y consultorías sin integración.","Recibir una solución atractiva que la organización no necesita."]}]},{"type":"list","label":"Objeciones frente a una propuesta B2B","items":["\"No tengo tiempo para otra formación o consultoría extensa.\"","\"Necesito resultados, no una conferencia inspiracional.\"","\"Mi equipo técnico ya sabe de esto; ¿qué valor adicional aporta?\"","\"Cada área tiene necesidades distintas.\"","\"¿Cómo se adapta a nuestro sector, presupuesto y restricciones?\"","\"¿Cómo vamos a medir impacto y retorno?\"","\"¿Qué riesgos jurídicos, de datos y reputación debemos considerar?\""]},{"type":"text","label":"Respuesta de Divergente","body":"La respuesta de Divergente debe ser ejecutiva y aplicada: diagnóstico, criterios de priorización, casos, hoja de ruta, formación diferenciada para equipos, acompañamiento y soluciones conectadas con procesos reales. No una exhibición de herramientas ni una promesa genérica de transformación."}]},{"title":"Comportamiento digital y consumo de autoridad","blocks":[{"type":"text","label":"Comportamiento digital","body":"Jaime o Diana no suele recorrer tutoriales largos ni seguir tendencias por entretenimiento. Consume información cuando una decisión, un riesgo o una oportunidad concreta entra en su agenda. LinkedIn, el CRM, los referidos, las conversaciones entre pares, los casos y las presentaciones ejecutivas son sus principales puertas de entrada. Puede ver un video de YouTube cuando se lo comparte alguien de confianza, cuando responde una pregunta estratégica o cuando necesita verificar la autoridad de Divergente."},{"type":"grid","columns":[{"label":"Búsquedas y preguntas posibles","items":["Cómo implementar inteligencia artificial en una empresa.","Estrategia de IA para organizaciones.","Gobernanza y riesgos de inteligencia artificial.","Cómo formar equipos para trabajar con IA.","Cómo medir el retorno de una automatización.","Qué debe saber un directivo sobre IA generativa.","Cómo liderar equipos que ya utilizan inteligencia artificial.","Hoja de ruta de transformación digital.","Cómo evaluar un proveedor tecnológico.","Gestión del conocimiento y automatización de procesos."]},{"label":"Qué valora en los contenidos","items":["Claridad, síntesis y lenguaje ejecutivo.","Casos concretos y resultados verificables.","Marcos que facilitan decisiones.","Riesgos, límites y condiciones de implementación.","Diferencias entre moda, piloto y capacidad real.","Relevancia para su sector y nivel de responsabilidad.","Perspectiva interdisciplinaria, no solo técnica.","Autoridad respaldada por experiencia institucional.","Recomendaciones sin exageraciones ni promesas vacías."]}]},{"type":"list","label":"Contenidos que pueden atraerlo","items":["\"Antes de comprar una solución de IA, responda estas siete preguntas.\"","\"Por qué la mayoría de los pilotos de inteligencia artificial no escalan.\"","\"Lo que un directivo debe saber de IA sin convertirse en técnico.\"","\"Su equipo ya utiliza IA: la pregunta es si la organización lo sabe.\"","\"Automatizar un proceso mal diseñado solo acelera el problema.\"","\"Cómo construir una hoja de ruta de IA en 90 días.\"","\"Gobernanza antes que herramientas.\"","\"Cómo evaluar a un proveedor de inteligencia artificial.\"","\"De pilotos dispersos a una capacidad organizacional.\"","\"Qué medir en IA más allá de las horas ahorradas.\""]}]},{"title":"Compra, conversión y relación con Divergente","blocks":[{"type":"list","label":"Detonantes de compra","body":"Jaime o Diana tiene mayor disposición a contratar cuando:","items":["La junta o la dirección solicita una estrategia de IA.","Se abre un nuevo ciclo presupuestal o de planeación.","La organización debe formar a un grupo o equipo completo.","Ocurre un incidente relacionado con datos, seguridad o uso inadecuado.","Asume un nuevo cargo o inicia una reestructuración.","Existe un cuello de botella operativo que afecta resultados.","Un competidor o institución comparable avanza más rápido.","Un líder interno presenta una oportunidad que necesita patrocinio.","Debe evaluar una propuesta tecnológica de alto impacto.","Necesita mostrar avances concretos dentro de un plazo definido."]},{"type":"table","headers":["Etapa","Qué ocurre"],"rows":[["Descubrimiento","Encuentra una publicación en LinkedIn, recibe un referido, conoce un caso o recibe un video compartido por su equipo."],["Reconocimiento","Comprende que el problema no es solo adquirir herramientas, sino alinear estrategia, personas, procesos y gobernanza."],["Confianza","Revisa casos, metodologías, experiencia institucional, conferencias y la capacidad de Divergente para traducir tecnología a decisiones."],["Evaluación","Participa en una conversación ejecutiva o diagnóstico; revisa alcance, resultados esperados, riesgos, tiempos y presupuesto."],["Compra","Contrata un diagnóstico, taller directivo, formación de equipos, consultoría, automatización o desarrollo personalizado."],["Implementación","Define patrocinadores, responsables, equipos, hoja de ruta, indicadores y mecanismos de seguimiento."],["Continuidad","Amplía la formación, implementa nuevos casos, consolida capacidades internas y mantiene acompañamiento estratégico."]]},{"type":"quote","label":"Promesa para Jaime y Diana","body":"Dirige la adopción de inteligencia artificial, datos y tecnología con criterio, alinea a tus equipos y convierte la transformación en resultados medibles, sin tener que convertirte en especialista técnico."}]},{"title":"Límites del perfil e hipótesis por validar","blocks":[{"type":"text","label":"Lo que no es este avatar","body":"No es una persona que busca tutoriales básicos, trucos rápidos o una comunidad de bajo costo para aprender herramientas por cuenta propia. Tampoco es necesariamente un ejecutivo técnico interesado en arquitectura avanzada, código o investigación de modelos. Su valor está en decidir, priorizar, alinear, patrocinar y responder por los resultados. No quiere delegar completamente la transformación: necesita comprenderla lo suficiente para ejercer liderazgo y supervisión."},{"type":"list","label":"Hipótesis que tendremos que validar","items":["Que los altos directivos consumen contenido cuando está presentado en lenguaje ejecutivo y conectado con decisiones reales.","Que sus dolores principales se relacionan más con equipos, gobernanza, priorización y riesgo que con el uso de herramientas.","Que LinkedIn, el CRM, los referidos y los casos generan más confianza que la publicación masiva de contenido.","Que YouTube funciona principalmente como prueba de autoridad y recurso compartido por equipos o aliados.","Que la conversación ejecutiva o el diagnóstico es el principal punto de conversión.","Que puede autorizar presupuesto o actuar como patrocinador interno de una contratación.","Que la formación de equipos puede ser la puerta de entrada hacia consultoría, automatización y desarrollo.","Que la experiencia de Divergente en cultura, turismo y sector público puede transferirse a otras organizaciones intensivas en conocimiento.","Que valora más una hoja de ruta aplicable que una certificación individual.","Que los casos, resultados y criterios de riesgo pesan más que la cantidad de herramientas presentadas."]},{"type":"text","label":"Decisiones pendientes para aterrizar el perfil","body":"Definir los tres sectores prioritarios, el tamaño de organización, el rango de presupuesto, la primera oferta de entrada y la unidad real de decisión: quién autoriza, quién recomienda, quién utilizará la solución y quién puede bloquearla."}]}]}'::jsonb
  where slug = 'diana';

update public.marketing_avatars
  set persona_sections = '{"role_title":"El Profesional que Construye Proyectos","tagline":"Audiencia principal de Instagram y TikTok · Comunidad Skool y experiencias formativas","channel":"Instagram · TikTok · YouTube","priority_offer":"Comunidad Skool","strategic_role":"Profesional que construye proyectos","sections":[{"title":"Identidad, contexto y momento del proyecto","blocks":[{"type":"text","label":"Identidad funcional","body":"Valentina o Juan es un profesional independiente, creador, emprendedor temprano o líder de una iniciativa que quiere convertir ideas, conocimientos y habilidades en un proyecto sostenible. Necesita integrar creatividad, tecnología, método y comunidad para avanzar con mayor claridad, consistencia y propósito. No busca únicamente aprender herramientas. Quiere encontrar una forma de trabajo que le permita diseñar, comunicar, probar y fortalecer un proyecto real sin perder su identidad ni avanzar en soledad."},{"type":"grid","columns":[{"label":"Perfil profesional","body":"Habitualmente puede ser:","items":["Artista, músico, diseñador, escritor o creador de contenidos.","Gestor cultural, productor o profesional de industrias creativas.","Emprendedor turístico o diseñador de experiencias.","Docente, facilitador, investigador o comunicador.","Profesional de bienestar, yoga, cuerpo o prácticas contemplativas.","Consultor, freelancer o prestador de servicios especializados.","Persona que desarrolla una marca, portafolio, metodología, curso o producto propio.","Profesional que combina un empleo con un proyecto personal en construcción."]},{"label":"Sectores y rasgo común","body":"Puede moverse entre cultura, creatividad, turismo, educación, bienestar, comunicación, tecnología, servicios profesionales o proyectos de impacto. Su característica común no es el sector. Es que construye con recursos limitados, cumple varios roles y necesita convertir conocimiento e ideas en una propuesta visible, útil y sostenible."}]},{"type":"list","label":"Momento del proyecto","body":"Valentina o Juan ya tiene una idea, una práctica, un servicio o un proyecto en marcha, pero el avance es irregular. Alterna momentos de entusiasmo con periodos de dispersión, exceso de información o falta de continuidad. Empieza a observar que:","items":["Tiene muchas ideas, pero le cuesta priorizarlas y terminarlas.","Consume contenidos, herramientas y cursos sin convertirlos en un sistema propio.","La IA puede ampliar su capacidad, pero teme usarla de forma genérica o perder su voz.","Necesita comunicar con constancia, aunque no quiere vivir pendiente de las redes.","Trabajar solo limita la retroalimentación, la disciplina y las oportunidades.","Su proyecto necesita estructura, validación y una relación más clara con ingresos o impacto."]},{"type":"quote","label":"Tensión principal","body":"\"Tengo ideas, capacidades y ganas de construir algo propio, pero me cuesta convertir todo eso en un proyecto sostenido sin perderme, agotarme o volverme una copia de lo que funciona en redes.\" Esta tensión es central para Divergente. Valentina y Juan quieren avanzar con método y tecnología, pero conservando criterio, identidad, curiosidad y propósito."}]},{"title":"Trabajo por resolver y capacidades necesarias","blocks":[{"type":"text","label":"Trabajo que necesita resolver","body":"Convertir ideas, conocimientos y motivaciones en un proyecto claro, comunicable y sostenible, utilizando creatividad, inteligencia artificial, herramientas digitales y acompañamiento colectivo para avanzar de manera consistente."},{"type":"table","headers":["Capacidad","Lo que necesita lograr"],"rows":[["Claridad y enfoque","Definir qué proyecto está construyendo, para quién, con qué problema y qué debe priorizar ahora."],["Diseño de proyectos","Traducir una idea en objetivos, acciones, entregables, pruebas y una ruta de avance."],["Pensamiento creativo","Explorar alternativas, relacionar disciplinas y construir una propuesta con identidad propia."],["Tecnología e IA aplicada","Usar herramientas para investigar, crear, organizar y producir sin delegar su criterio."],["Comunicación y contenido","Explicar su proyecto, generar confianza y sostener una presencia digital coherente."],["Validación y sostenibilidad","Probar necesidades, ajustar la propuesta y conectar el proyecto con ingresos, alianzas o impacto."],["Comunidad y colaboración","Recibir retroalimentación, compartir aprendizajes y avanzar acompañado por pares."]]},{"type":"text","label":"Problema principal","body":"El problema de Valentina o Juan no es la falta de ideas ni de información. Es la dificultad para convertir ambos recursos en decisiones, hábitos, entregables y un proyecto que avance con continuidad. Consume referencias, tutoriales y tendencias, pero con frecuencia termina con conocimientos dispersos, nuevas posibilidades abiertas y poca claridad sobre el siguiente paso."},{"type":"list","label":"Problemas secundarios","items":["Le cuesta escoger entre varias ideas y oportunidades.","Empieza proyectos con energía, pero pierde ritmo o los abandona.","Aprende de manera autodidacta sin una ruta ni retroalimentación constante.","No sabe cómo convertir su conocimiento en una oferta, experiencia o producto.","Publica de manera irregular o sin una narrativa reconocible.","Tiene dificultad para hablar de ventas, precios y sostenibilidad económica.","Se compara con creadores o proyectos que parecen avanzar más rápido.","Acumula herramientas, cursos y plantillas que no integra a su práctica.","Trabaja solo y carece de espacios para probar ideas con personas de confianza.","Quiere usar IA, pero teme homogeneizar su voz o producir contenido vacío.","Debe combinar su proyecto con empleo, clientes, estudio o responsabilidades personales.","No siempre distingue entre una buena idea, una oportunidad real y una distracción.","Puede confundir actividad constante con progreso significativo.","Tiene recursos limitados y necesita priorizar con mucho cuidado."]}]},{"title":"Transformación, motivaciones y barreras","blocks":[{"type":"list","label":"Resultado deseado","body":"Valentina o Juan quiere convertirse en una persona capaz de:","items":["Definir un proyecto central y una ruta de avance realista.","Transformar ideas en entregables, pruebas y experiencias concretas.","Construir una práctica semanal que no dependa únicamente de la motivación.","Usar IA y herramientas digitales sin perder su voz ni su criterio.","Comunicar con claridad qué hace, para quién y por qué importa.","Diseñar contenidos conectados con su proyecto y no publicar por obligación.","Validar necesidades, recibir retroalimentación y ajustar rápidamente.","Construir una oferta, portafolio o sistema de ingresos progresivo.","Relacionarse con personas de otros sectores y generar colaboraciones.","Avanzar acompañado, con referencias, estructura y responsabilidad compartida."]},{"type":"text","label":"Transformación buscada","body":"No busca convertirse en una máquina de producir contenido ni seguir una fórmula única de emprendimiento. Busca pasar de la dispersión y el avance intermitente a una práctica creativa y profesional con método, comunidad, herramientas y una dirección propia."},{"type":"grid","columns":[{"label":"Motivaciones profundas","body":"Su motivación visible es aprender, organizarse o lanzar un proyecto. Sus motivaciones profundas pueden ser:","items":["Construir autonomía profesional y creativa.","Dar forma a una idea que considera importante.","Vivir de su conocimiento, práctica o talento.","Encontrar reconocimiento sin traicionar su identidad.","Generar impacto en una comunidad o territorio.","Sentirse acompañado por personas con intereses compatibles.","Combinar creatividad, tecnología y propósito.","Tener una vida laboral más flexible y significativa.","Demostrar que puede terminar y sostener lo que empieza."]},{"label":"Miedos","items":["Que su proyecto nunca pase de ser una idea.","Exponerse y recibir poco interés o críticas.","Invertir tiempo y dinero sin resultados visibles.","Perder autenticidad al seguir tendencias o utilizar IA.","No ser suficientemente experto para enseñar, vender o publicar.","Quedar atrapado en comparación, perfeccionismo o procrastinación.","Entrar a otra comunidad que después quede inactiva.","No poder sostener el ritmo junto con sus otras responsabilidades.","Convertir algo que ama en una obligación agotadora."]}]},{"type":"list","label":"Objeciones frente a la comunidad Skool","items":["\"Ya hay demasiadas comunidades y casi ninguna se mantiene activa.\"","\"No tengo tiempo para seguir otro programa.\"","\"Puedo aprender todo esto gratis en internet.\"","\"No sé si mi proyecto está suficientemente avanzado.\"","\"¿Será demasiado general para mi sector?\"","\"Me cuesta participar y mostrar procesos que todavía no están listos.\"","\"No quiero acumular más contenido sin aplicarlo.\"","\"¿Voy a recibir retroalimentación real o solo videos grabados?\""]},{"type":"text","label":"Respuesta de Divergente","body":"La comunidad debe demostrar movimiento, aplicación y acompañamiento: retos breves, laboratorios, sesiones en vivo, plantillas, retroalimentación entre pares, seguimiento de avances y rutas flexibles para proyectos en distintas etapas. El valor no está en acumular clases, sino en convertir aprendizaje en progreso visible."}]},{"title":"Comportamiento digital y consumo de contenido","blocks":[{"type":"text","label":"Comportamiento digital","body":"Valentina o Juan descubre ideas, referentes y posibilidades principalmente en Instagram y TikTok. Guarda publicaciones, comparte contenidos con amigos, sigue procesos creativos y utiliza los mensajes directos para acercarse a personas o proyectos. YouTube funciona como espacio de profundidad cuando necesita aprender una metodología, resolver una herramienta o entender un proceso completo. También puede consumir newsletters, podcasts y comunidades especializadas, pero su relación cotidiana con Divergente comienza en formatos visuales, breves y cercanos."},{"type":"grid","columns":[{"label":"Búsquedas y preguntas posibles","items":["Cómo organizar un proyecto creativo.","Cómo convertir una idea en un proyecto.","Cómo usar IA sin perder mi estilo.","Cómo crear contenido para mi proyecto.","Cómo validar una idea antes de lanzarla.","Cómo construir una marca personal auténtica.","Cómo monetizar un proyecto cultural o creativo.","Cómo crear una comunidad alrededor de un proyecto.","Herramientas para freelancers y creadores.","Cómo dejar de empezar proyectos y no terminarlos."]},{"label":"Qué valora en los contenidos","items":["Procesos reales, incluidos errores y ajustes.","Una estética cuidada sin perder claridad.","Lenguaje cercano, reflexivo y no excesivamente corporativo.","Ejercicios, preguntas y plantillas aplicables.","Casos de personas con recursos y equipos pequeños.","Perspectivas críticas sobre productividad, tendencias e IA.","Ideas que conectan creatividad, tecnología y vida cotidiana.","Referentes de distintos sectores y disciplinas.","Mensajes que inspiran acción sin promover agotamiento."]}]},{"type":"list","label":"Contenidos que pueden atraerlo","items":["\"No necesitas otra idea: necesitas un sistema para terminar la que ya tienes.\"","\"Cómo pasar de un proyecto disperso a una ruta de 30 días.\"","\"Usa inteligencia artificial sin perder tu voz.\"","\"Por qué publicar mucho no significa construir comunidad.\"","\"Una metodología para convertir conocimiento en una oferta.\"","\"El problema no es la falta de disciplina, sino el diseño de tu proyecto.\"","\"Qué hacer cuando tienes demasiados intereses.\"","\"Cómo probar una idea antes de invertir meses en ella.\"","\"Crear acompañado: por qué una comunidad puede acelerar tu proyecto.\"","\"Tecnología para crear más espacio, no más ruido.\""]}]},{"title":"Compra, conversión y relación con Divergente","blocks":[{"type":"list","label":"Detonantes de compra","body":"Valentina o Juan tiene mayor disposición a entrar a la comunidad cuando:","items":["Decide retomar o lanzar un proyecto propio.","Se siente estancado después de consumir mucha información.","Necesita preparar una convocatoria, portafolio, lanzamiento o propuesta.","Quiere utilizar IA, pero necesita una ruta aplicada y crítica.","Encuentra un reto o laboratorio conectado con un problema inmediato.","Observa el avance de otra persona con un proyecto comparable.","Busca una red que combine aprendizaje, retroalimentación y colaboración.","Comprende que la comunidad no exige tener un proyecto terminado.","Encuentra una membresía accesible que puede probar sin gran riesgo.","Ve evidencia de actividad, acompañamiento y resultados dentro de Skool."]},{"type":"table","headers":["Etapa","Qué ocurre"],"rows":[["Descubrimiento","Encuentra un Reel, TikTok, carrusel o historia que nombra una tensión de su proceso creativo o profesional."],["Reconocimiento","Comprende que su problema no es la falta de ideas, sino la ausencia de método, foco, retroalimentación y continuidad."],["Confianza","Consume procesos, metodologías, sesiones, casos y contenidos donde Divergente conecta creatividad, tecnología y pensamiento crítico."],["Evaluación","Revisa la actividad de Skool, los formatos, la frecuencia, los retos, el tipo de comunidad y el costo de entrada."],["Compra","Ingresa porque percibe una forma accesible de avanzar acompañado y aplicar lo aprendido a su proyecto."],["Activación","Completa una ruta inicial, presenta su proyecto, participa en un reto y consigue un primer avance visible."],["Continuidad","Mantiene la membresía, colabora con otros miembros y puede avanzar hacia cursos, bootcamps, laboratorios o servicios."]]},{"type":"quote","label":"Promesa para Valentina y Juan","body":"Convierte tus ideas en proyectos con método, comunidad y herramientas digitales, sin perder tu identidad ni tener que avanzar en soledad."}]},{"title":"Límites del perfil e hipótesis por validar","blocks":[{"type":"text","label":"Lo que no es este avatar","body":"No es una persona que busca únicamente entretenimiento, tendencias o trucos rápidos para aumentar seguidores. Tampoco es un alto directivo que contrata una transformación organizacional ni el propietario de una microempresa consolidada cuya prioridad principal sea ordenar una operación diaria; ese último patrón corresponde al cuarto avatar en evaluación. Puede generar ingresos o tener clientes, pero su necesidad central sigue siendo construir, enfocar y sostener un proyecto propio. Su valor está en relacionar identidad, creatividad, método, tecnología, comunidad y acción."},{"type":"list","label":"Hipótesis que tendremos que validar","items":["Que el patrón común atraviesa cultura, turismo, educación, bienestar, comunicación y servicios profesionales.","Que su problema principal es la dispersión y la falta de continuidad, no la falta de ideas.","Que Instagram y TikTok son los principales canales de descubrimiento y afinidad.","Que YouTube funciona como espacio complementario de profundidad y confianza.","Que valora una comunidad activa, pequeña y aplicada más que una biblioteca extensa de cursos.","Que los retos, laboratorios y sesiones en vivo aumentan activación y permanencia.","Que el precio accesible reduce la barrera de entrada, pero la continuidad depende de avances visibles.","Que identidad, propósito y autenticidad son variables relevantes al utilizar IA.","Que existe disposición a mostrar procesos incompletos cuando el entorno es seguro y útil.","Que la comunidad puede conducir posteriormente a bootcamps, productos y servicios de mayor valor.","Que \"profesional que construye proyectos\" es un nombre reconocible y suficientemente amplio.","Que las personas prefieren rutas por etapa del proyecto antes que rutas separadas únicamente por sector."]},{"type":"text","label":"Decisiones pendientes para aterrizar el perfil","body":"Validar los tres subgrupos prioritarios, el precio mensual aceptable, la frecuencia de encuentros, las condiciones que demuestran que la comunidad está activa, la primera ruta de bienvenida y el equilibrio entre contenidos transversales y laboratorios por sector."}]}]}'::jsonb
  where slug = 'juan';

update public.marketing_avatars
  set persona_sections = '{"role_title":"El Emprendedor Operador","tagline":"Propietario de una microempresa · Comprador de soluciones digitales","channel":"Instagram · WhatsApp · YouTube · Google","priority_offer":"Soluciones digitales y sistemas","strategic_role":"Emprendedor operador","sections":[{"title":"Identidad, negocio y momento empresarial","blocks":[{"type":"text","label":"Definición estratégica","body":"Andrés o Laura no es principalmente comprador de formación. Es propietario o administrador de una microempresa con un equipo de entre dos y cinco personas. Dirige, vende, administra, atiende clientes y resuelve la operación. Necesita utilizar inteligencia artificial, automatización y herramientas digitales para multiplicar su capacidad sin aumentar demasiado sus costos ni convertirse en especialista técnico. La formación puede acompañar la implementación, pero no debe ser la promesa principal. Su función comercial es comprar sistemas sencillos que le permitan atender, vender, organizar y operar mejor su negocio sin ampliar excesivamente el equipo."},{"type":"text","label":"Identidad funcional","body":"Andrés o Laura es propietario, fundador o administrador de una microempresa que necesita integrar inteligencia artificial, automatización y herramientas digitales para reducir tareas repetitivas, atender mejor, vender más y organizar su negocio. No busca una transformación digital abstracta. Busca resolver problemas concretos: responder mensajes, organizar reservas, dar seguimiento a clientes, crear contenido, preparar cotizaciones, recordar pagos, consolidar información, controlar pedidos, evitar que se pierdan oportunidades y entender qué está ocurriendo en el negocio. La tecnología le interesa cuando puede traducirse rápidamente en tiempo, organización, clientes o ingresos."},{"type":"grid","columns":[{"label":"Perfil empresarial","body":"Puede ser propietario o administrador de:","items":["Minimercado o comercio de barrio.","Restaurante, cafetería o bar pequeño.","Tienda de discos, librería o comercio especializado.","Estudio de yoga, bienestar o actividad física.","Consultorio odontológico o servicio de salud.","Agencia pequeña.","Emprendimiento cultural.","Operador o experiencia turística.","Alojamiento pequeño.","Taller creativo.","Productora.","Tienda física o digital.","Empresa familiar.","Servicio profesional con pocos colaboradores."]},{"label":"Rasgo común","body":"Su característica común no es el sector. Es la estructura del negocio: la empresa depende demasiado de la presencia, conocimiento y energía de su propietario. Andrés o Laura decide, paga, supervisa y también opera. La misma persona que toma decisiones suele implementar, atender urgencias y resolver tareas cotidianas."}]},{"type":"text","label":"Momento empresarial","body":"El negocio ya existe. Puede tener clientes frecuentes y una reputación construida, pero gran parte de la operación continúa dependiendo de procesos manuales, conversaciones de WhatsApp, hojas de cálculo, notas, memoria personal y trabajo improvisado. Probablemente ya utiliza WhatsApp Business, Instagram, hojas de cálculo, aplicaciones de pagos, calendarios, algún sistema de reservas, ChatGPT u otra herramienta de IA, plataformas de domicilios o comercio electrónico y aplicaciones sectoriales. Sin embargo, estas herramientas funcionan de manera aislada. Puede generar textos con IA, pero todavía no tiene un sistema para conectar consultas, clientes, reservas, contenidos, ventas y seguimiento."},{"type":"quote","label":"Tensiones principales","body":"\"La inteligencia artificial podría ayudarme muchísimo, pero no tengo tiempo para aprender veinte herramientas ni dinero para contratar una solución empresarial enorme.\" \"Sé que debo delegar y organizar el negocio, pero muchas cosas todavía dependen de mí.\" La propuesta de Divergente debe mostrarle que no necesita convertir su negocio en una empresa tecnológica. Necesita crear un sistema pequeño, comprensible y sostenible."}]},{"title":"Trabajo por resolver, capacidades y problemas","blocks":[{"type":"text","label":"Trabajo que necesita resolver","body":"Utilizar tecnología e inteligencia artificial para aumentar la capacidad operativa y comercial de una pequeña empresa sin incrementar innecesariamente el equipo, los costos o la complejidad."},{"type":"table","headers":["Capacidad","Lo que necesita conseguir"],"rows":[["Organización operativa","Tener claridad sobre tareas, clientes, reservas, pedidos y pendientes."],["Atención al cliente","Responder más rápido y evitar que se pierdan conversaciones."],["Seguimiento comercial","Recordar interesados, cotizaciones y oportunidades."],["Producción de contenido","Comunicar el negocio sin dedicar horas diariamente."],["Automatización sencilla","Conectar tareas repetitivas sin crear sistemas difíciles de mantener."],["Lectura del negocio","Comprender ventas, demanda, comportamiento y resultados."],["Dirección práctica","Saber qué delegar, qué automatizar y qué debe seguir siendo humano."]]},{"type":"text","label":"Problema principal","body":"El negocio depende excesivamente de su propietario. Andrés o Laura puede ausentarse unas horas y encontrar mensajes sin responder, reservas sin confirmar, cotizaciones pendientes, información dispersa, clientes sin seguimiento, publicaciones sin realizar, tareas que nadie sabía que debía ejecutar y decisiones que únicamente él o ella podía tomar. La falta de sistemas limita tanto el crecimiento como su calidad de vida."},{"type":"list","label":"Problemas secundarios","items":["Atiende demasiadas tareas diferentes durante el día.","Utiliza varias herramientas que no están conectadas.","No cuenta con un equipo tecnológico.","Le cuesta delegar porque los procesos no están documentados.","Pierde clientes por respuestas tardías.","Publica contenido de manera irregular.","No sabe cuáles automatizaciones son realmente necesarias.","Tiene datos, pero no los convierte en decisiones.","Depende de conversaciones y notas para recordar compromisos.","Sus colaboradores preguntan constantemente qué deben hacer.","Compra herramientas que después no utiliza.","Confunde digitalizar una tarea con mejorar el proceso.","No tiene tiempo para aprender sistemas complejos.","Le preocupa asumir nuevos costos mensuales.","Vive resolviendo urgencias y posterga las mejoras estructurales."]}]},{"title":"Resultado deseado, motivaciones y barreras","blocks":[{"type":"list","label":"Resultado deseado","body":"Andrés o Laura quiere construir una empresa pequeña que pueda funcionar sin exigirle atención permanente. No quiere necesariamente construir una empresa gigantesca. Puede querer simplemente un negocio rentable, ordenado, sostenible y menos dependiente de su presencia.","items":["Recuperar tiempo.","Responder oportunamente.","Tener una operación organizada.","Dar seguimiento a los clientes.","Delegar con mayor claridad.","Crear contenido con menor esfuerzo.","Tomar decisiones con información.","Reducir errores.","Evitar contratar personas únicamente para tareas repetitivas.","Mantener una atención cercana.","Crecer sin perder el control.","Poder ausentarse sin que el negocio se detenga."]},{"type":"grid","columns":[{"label":"Motivaciones profundas","body":"Su motivación visible es ahorrar tiempo o vender más. Detrás aparecen motivaciones más profundas:","items":["Sentir que controla el negocio y no que el negocio lo controla.","Disminuir el agotamiento.","Proteger el esfuerzo invertido durante años.","Profesionalizar su empresa.","Tener más tiempo personal.","Estar presente en las actividades que realmente generan valor.","Dejar de operar permanentemente desde la urgencia.","Competir con negocios que tienen equipos más grandes.","Ofrecer una experiencia de cliente más consistente.","Preparar el negocio para crecer.","Demostrar que una empresa pequeña también puede trabajar con buenos sistemas."]},{"label":"Miedos","items":["Gastar dinero en una tecnología que no entienda.","Depender de un proveedor.","Que una automatización falle y afecte a sus clientes.","Perder el trato humano.","Exponer información privada.","Añadir más herramientas y aumentar el desorden.","Pagar suscripciones que no utiliza.","Que su equipo rechace el sistema.","Descubrir que necesita invertir más de lo previsto.","No tener tiempo para implementar lo aprendido.","Recibir una solución demasiado técnica.","Que la herramienta funcione durante un mes y después quede abandonada."]}]},{"type":"list","label":"Objeciones","items":["Mi negocio es demasiado pequeño para necesitar esto.","Yo puedo seguir respondiendo personalmente.","No tengo presupuesto para un desarrollo.","Mis clientes prefieren hablar con una persona.","Ya probé una herramienta y no funcionó.","Mi equipo no es muy tecnológico.","No tengo tiempo para hacer un curso.","No quiero pagar diez plataformas.","Cada negocio es distinto; no sé si esto me servirá.","Prefiero contratar a alguien antes que aprender todo eso."]},{"type":"text","label":"Respuesta de Divergente","body":"La respuesta no debería ser vender más tecnología. Debe demostrar: menos herramientas, mejor seleccionadas, conectadas a un problema concreto y acompañadas por un proceso que el negocio pueda sostener. En negocios relacionados con salud o información sensible, la privacidad y el manejo de datos deben tratarse como una variable específica de validación y diseño."}]},{"title":"Función comercial y diferencia frente a otros avatares","blocks":[{"type":"text","label":"Categoría comercial","body":"Andrés / Laura deben quedar en una categoría comercial distinta. No son principalmente compradores de formación, sino clientes de soluciones digitales para microempresas. La formación puede acompañar la implementación, pero no debe ser la promesa principal. Su ruta principal pertenece a Productos Divergente: sistemas, automatizaciones, agentes, soluciones digitales, analítica aplicada y desarrollos sencillos que resuelvan un problema concreto."},{"type":"table","headers":["Variable","Definición"],"rows":[["Tipo de cliente","Propietario o administrador de una microempresa."],["Tamaño habitual","Equipo de dos a cinco personas."],["Rol","Decide, paga, supervisa y también opera."],["Necesidad principal","Reducir carga operativa y evitar perder clientes."],["Oferta prioritaria","Soluciones digitales, automatizaciones y sistemas de ventas."],["Formación","Complementaria para adopción y uso."],["Conversión principal","Diagnóstico breve y conversación por WhatsApp."]]},{"type":"table","headers":["Variable","Jaime / Diana","Andrés / Laura"],"rows":[["Estructura","Dirigen áreas, instituciones o empresas con equipos.","Dirigen una empresa pequeña y también realizan tareas operativas."],["Compra","Compran transformación organizacional.","Compran una solución concreta."],["Implementación","Pueden delegar la implementación.","Participan directamente en la implementación."],["Ciclo comercial","Más largo.","Más corto."],["Presupuesto","Presupuesto empresarial.","Presupuesto limitado y sensible al retorno."],["Dolor","Estrategia, gobernanza y gestión de equipos.","Ventas, reservas, atención, seguimiento y organización."],["Preferencia","Valoran propuestas completas.","Valoran soluciones simples, rápidas y comprensibles."]]},{"type":"quote","label":"Pregunta que intenta resolver","body":"Jaime o Diana preguntan: \"¿Cómo transformo esta organización?\" Andrés o Laura preguntan: \"¿Cómo hago para que este negocio funcione mejor sin tener que hacerlo todo yo?\""}]},{"title":"Qué vender primero y por qué","blocks":[{"type":"text","label":"Primera oferta recomendada","body":"La entrada más sólida no debería ser \"automatización\" en abstracto ni \"inteligencia artificial para empresas\". Debe venderse un resultado reconocible: Un sistema sencillo para evitar que se pierdan clientes, organizar el seguimiento y reducir tareas repetitivas."},{"type":"list","label":"Sistema de ventas y atención para pequeños negocios","body":"Puede incluir, dependiendo del negocio:","items":["Organización de contactos e interesados.","Registro de clientes.","Seguimiento de cotizaciones.","Respuestas frecuentes.","Automatización inicial de WhatsApp.","Recordatorios de reservas o citas.","Formularios y captura de información.","Panel sencillo de seguimiento.","Integración con calendario.","Base de conocimiento del negocio.","Reporte básico de clientes, solicitudes y ventas.","Capacitación corta para el equipo.","Mantenimiento mensual."]},{"type":"text","label":"Por qué empezar por ventas y atención","body":"Esta solución resulta más fácil de comprender y comprar porque conecta directamente con tres dolores: pierdo oportunidades; paso demasiado tiempo respondiendo lo mismo; no sé a quién debo hacerle seguimiento."},{"type":"table","headers":["Tipo de negocio","Primera necesidad vendible"],"rows":[["Estudio de yoga","Reservas, recordatorios, planes, pagos y seguimiento."],["Odontología o salud","Citas, confirmaciones, preguntas frecuentes y reactivación."],["Restaurante o bar","Reservas, eventos, pedidos y clientes frecuentes."],["Tienda de discos","Catálogo, disponibilidad, recomendaciones y pedidos."],["Turismo","Consultas, cotizaciones, reservas y seguimiento."],["Minimercado","Pedidos, promociones, clientes frecuentes y domicilios."],["Empresa cultural","Inscripciones, programación, públicos y comunicaciones."],["Servicios profesionales","Captura de prospectos, reuniones, propuestas y seguimiento."]]},{"type":"text","label":"Orden comercial","body":"Vender mejor → operar mejor → comprender y crecer."}]},{"title":"Arquitectura de productos para Andrés / Laura","blocks":[{"type":"grid","columns":[{"label":"Sistemas para vender y atender","body":"Es la línea que debería aparecer primero en la comunicación.","items":["Sistema de seguimiento de clientes.","CRM simplificado.","Agente de WhatsApp.","Cotizaciones automatizadas.","Reservas y citas.","Recordatorios.","Catálogo conversacional.","Recuperación de clientes.","Automatización de preguntas frecuentes.","Landing comercial conectada con WhatsApp."]},{"label":"Sistemas para operar","body":"Aparecen después de resolver el frente comercial.","items":["Gestión de pedidos.","Organización de tareas.","Documentación de procesos.","Base de conocimiento.","Gestión de inventario sencilla.","Consolidación de formularios y archivos.","Automatizaciones administrativas.","Integración entre herramientas.","Panel operativo."]}]},{"type":"list","label":"Sistemas para comprender y crecer","body":"Corresponden a la línea de analítica y estudios:","items":["Analítica de ventas.","Segmentación de clientes.","Análisis de comentarios.","Encuestas.","Estudios de mercado.","Estudios de públicos.","Mapas y análisis territorial.","Identificación de oportunidades.","Recomendaciones con IA.","Evaluación del impacto."]},{"type":"text","label":"Escalera de ofertas","body":"Este avatar necesita una escalera distinta a la de Jaime y Diana."},{"type":"table","headers":["Nivel","Oferta"],"rows":[["Entrada gratuita","Videos, guías, diagnósticos, plantillas, listas de procesos automatizables, casos por sector y webinars breves."],["Oferta de entrada","Taller práctico, curso corto, kit de herramientas, diagnóstico exprés, sesión grupal o ruta de automatización básica."],["Oferta intermedia","Bootcamp para pequeños negocios, programa de implementación acompañada, línea especializada dentro de Skool o laboratorio por sector."],["Oferta de mayor valor","Implementación de automatizaciones, agente de WhatsApp, seguimiento de clientes, reservas, contenidos, página o comercio digital, integración de información, mantenimiento y mejora continua."]]},{"type":"text","label":"Decisión sobre comunidad","body":"No se recomienda crear inmediatamente una segunda comunidad. Puede comenzar como una ruta o espacio específico dentro de Skool y separarse únicamente cuando exista suficiente volumen."}]},{"title":"Canales más óptimos para descubrir, validar y vender","blocks":[{"type":"grid","columns":[{"label":"Instagram","body":"Debe ser el principal canal de descubrimiento para negocios locales, turismo, bienestar, cultura, comercio y gastronomía. El contenido debe mostrar situaciones concretas: antes y después de un proceso, casos por tipo de negocio, errores comunes, tareas que pueden simplificarse, demostraciones breves, testimonios, pantallas de sistemas funcionando y resultados en tiempo, respuestas o seguimiento. La llamada a la acción debe conducir a WhatsApp, no a una explicación extensa de tecnología."},{"label":"WhatsApp","body":"Debe ser el principal canal de conversión. Este avatar quiere contar su caso mediante una conversación, audio o ejemplo real antes que completar formularios extensos. Ruta recomendada: contenido → WhatsApp → diagnóstico breve → propuesta de sistema → implementación."}]},{"type":"grid","columns":[{"label":"Google y Google Maps","body":"Son importantes para captar personas que ya están buscando una solución: automatización para restaurante, sistema de reservas para estudio de yoga, WhatsApp automático para negocios, CRM para pequeña empresa, página web para turismo o sistema para organizar clientes. Google Maps también puede utilizarse como fuente de prospección sectorial: identificar negocios, analizar su presencia digital y construir campañas o contactos específicos."},{"label":"Alianzas y CRM","body":"Puede ser uno de los canales más rentables.","items":["Cámaras de comercio.","Asociaciones de comerciantes.","Redes culturales.","Operadores turísticos.","Coworkings.","Asociaciones de bienestar.","Contadores.","Agencias de marketing.","Diseñadores de marca.","Proveedores de software.","Clientes actuales.","Bases de datos sectoriales de Divergente."]}]},{"type":"grid","columns":[{"label":"Youtube","body":"No tiene que ser el principal canal de captación, pero sí de validación y autoridad. Los videos deben orientarse a problemas y mostrar procesos completos, casos, comparaciones y criterios de decisión.","items":["Cómo organizar los clientes que llegan por WhatsApp.","Qué automatizar primero en un negocio pequeño.","Cómo implementar reservas sin perder el trato humano.","Cuánto cuesta realmente no hacer seguimiento.","Cómo diseñamos un sistema para una tienda de discos.","Qué puede automatizar un estudio de yoga.","Por qué una empresa pequeña también necesita procesos."]},{"label":"TikTok y LinkedIn","body":"TikTok es útil para alcance y reconocimiento, especialmente mediante ejemplos visuales o humor cotidiano. Debe conducir a Instagram, YouTube o WhatsApp. LinkedIn es secundario para comercios y negocios locales, pero relevante para consultores, agencias, servicios profesionales, salud, empresas turísticas B2B, fundadores y pequeñas empresas que venden a otras empresas."}]}]},{"title":"Lenguaje, mensajes y sistema de contenido","blocks":[{"type":"text","label":"Cómo hablarle","body":"El lenguaje debe ser directo, concreto y ligado a situaciones cotidianas. No conviene comenzar con categorías tecnológicas complejas; se debe iniciar por el problema, el resultado y el funcionamiento cotidiano del negocio."},{"type":"grid","columns":[{"label":"Lenguaje que conviene utilizar","items":["Organizar.","Ahorrar tiempo.","Responder mejor.","Evitar perder clientes.","Simplificar.","Dar seguimiento.","Delegar.","Tener control.","Reducir tareas repetitivas.","Conectar herramientas.","Hacer que el negocio funcione sin depender de todo el tiempo del propietario.","Empezar con una solución pequeña.","Construir únicamente lo necesario."]},{"label":"Lenguaje que conviene evitar al principio","items":["Transformación digital integral.","Arquitectura tecnológica.","Infraestructura de inteligencia artificial.","Ecosistema omnicanal.","Automatización hiperpersonalizada.","Modelos autónomos.","Agentes multimodales.","Implementación empresarial de gran escala."]}]},{"type":"quote","label":"Promesas principales","body":"\"Haz que tu negocio funcione mejor con inteligencia artificial y automatización, sin convertirte en técnico ni llenar tu empresa de herramientas.\" \"Organiza, automatiza y fortalece tu pequeña empresa para que no todo dependa de ti.\" \"Creamos sistemas sencillos para que tu negocio atienda mejor, haga seguimiento a sus clientes y reduzca tareas repetitivas.\" \"Tu negocio no necesita más herramientas. Necesita que las herramientas que ya utiliza trabajen juntas.\" \"Organizamos la atención, las ventas y las tareas de tu negocio para que no todo dependa de ti.\""},{"type":"table","headers":["Dolor","Mensaje"],"rows":[["No responde a tiempo","Evita perder clientes por mensajes sin seguimiento."],["Todo depende del propietario","Haz que el negocio funcione incluso cuando no estás."],["Demasiadas tareas manuales","Reduce las tareas que repites todos los días."],["Herramientas dispersas","Conecta WhatsApp, formularios, calendario y clientes."],["Poco presupuesto","Empieza con un sistema pequeño y escalable."],["Temor a perder cercanía","Automatiza lo repetitivo y conserva la atención humana."],["No sabe qué necesita","Primero diagnosticamos el proceso; después elegimos la tecnología."]]},{"type":"table","headers":["Pilar","Enfoque"],"rows":[["Tiempo y operación","Tareas que consumen horas; organización de pedidos, reservas, documentos, información y pendientes."],["Clientes y seguimiento","WhatsApp, consultas, cotizaciones, recordatorios, atención, bases de clientes y recuperación de oportunidades."],["Contenido y comunicación","Publicaciones, adaptación de contenidos, respuestas frecuentes, campañas y calendarios."],["Ventas","Seguimiento de interesados, embudos sencillos, productos, promociones y organización comercial."],["Datos para decisiones","Lectura básica de ventas, productos, horarios, clientes, demanda y comportamiento."],["Procesos y automatización","Qué automatizar, qué no automatizar y cómo comenzar sin destruir el trato humano."],["Casos por sector","Restaurante, estudio de yoga, consultorio, tienda de discos, alojamiento, turismo, bar, comercio, proyecto cultural y servicio profesional."]]}]},{"title":"Contenidos, detonantes y conversión","blocks":[{"type":"grid","columns":[{"label":"Contenidos que pueden atraerlo","items":["Cinco tareas que una pequeña empresa ya no debería hacer manualmente.","Cómo organizar los clientes que llegan por WhatsApp.","La automatización que necesita un restaurante pequeño.","Cómo usar IA en un estudio de yoga sin perder el trato humano.","Tres formas de perder clientes por falta de seguimiento.","No necesitas un software empresarial para empezar.","Cómo saber qué automatizar primero.","El dueño de una empresa no debería ser su propio sistema de información.","Cómo crear contenido para un mes sin pasar un mes creándolo.","IA para negocios pequeños: por dónde comenzar.","Antes de contratar otra persona, revisa estas tareas.","Una empresa pequeña también necesita procesos.","Cómo hacer que tu negocio funcione cuando no estás."]},{"label":"Detonantes de compra","items":["Está saturado de trabajo.","Pierde clientes por falta de respuesta.","Contrata a una nueva persona y no sabe cómo delegar.","Abre una segunda sede o canal.","Aumenta el volumen de mensajes.","Empieza a vender por internet.","Tiene dificultades para organizar reservas.","Su negocio crece, pero la operación no.","Un colaborador clave se retira.","Necesita producir contenido constantemente.","Descubre una herramienta, pero no sabe cómo implementarla.","Observa un caso similar a su negocio.","Calcula cuánto tiempo pierde en tareas repetitivas.","Comprende que puede empezar con una solución pequeña."]}]},{"type":"text","label":"Sistema de conversión recomendado","body":"Ruta 1. Contenido corto: Reel o TikTok sobre un problema reconocible → caso o explicación ampliada → llamada a diagnóstico → WhatsApp → taller, implementación o Skool. Ruta 2. YouTube: video sobre una solución concreta → plantilla o diagnóstico → conversación por WhatsApp → propuesta de sistema. Ruta principal de venta: contenido práctico y casos → diagnóstico → solución de ventas y atención → automatizaciones adicionales → analítica y mejora continua."},{"type":"list","label":"Diagnóstico de entrada","body":"Una conversación de 20 a 30 minutos con una matriz sencilla. El resultado debe ser un mapa de prioridades, no una lista de herramientas.","items":["¿Cómo llegan los clientes?","¿Dónde se registran?","¿Quién responde?","¿Qué tareas se repiten?","¿Dónde se pierde información?","¿Qué depende del propietario?","¿Qué herramientas utiliza actualmente?","¿Cuál es el costo del problema?","¿Qué debería seguir siendo humano?","¿Qué resultado necesita en los próximos 30 días?"]},{"type":"table","headers":["Nivel","Objetivo y alcance"],"rows":[["Inicial: sistema esencial","Resolver un problema concreto: reservas, seguimiento, cotizaciones, formulario y base de clientes, respuestas frecuentes o calendario de contenidos."],["Crecimiento: sistema conectado","Integrar WhatsApp, landing, formularios, CRM, calendario, reportes y automatizaciones."],["Personalizado: solución a la medida","Construir plataforma, aplicación, catálogo, comercio electrónico, recomendador, analítica, agente personalizado o integración de fuentes."]]}]},{"title":"Papel de la formación, hipótesis y conclusión estratégica","blocks":[{"type":"text","label":"Papel de la formación","body":"La formación no desaparece; cambia de posición. No se vende inicialmente \"aprende automatización\". Se incluye dentro de la solución: \"instalamos el sistema y capacitamos a tu equipo para que pueda utilizarlo y sostenerlo\". Después de la implementación, Andrés o Laura puede entrar a Skool, talleres de actualización, sesiones grupales, programas de acompañamiento, formación para su equipo o un bootcamp cuando quiera desarrollar mayor autonomía."},{"type":"text","label":"Lo que no es este avatar","body":"No es un profesional que busca únicamente desarrollar capacidades para ascender dentro de una organización; ese patrón corresponde a Mateo / Mariana. No es un alto directivo que contrata una transformación organizacional compleja; ese patrón corresponde a Jaime / Diana. Tampoco es una persona cuyo problema principal es convertir una idea en un proyecto y encontrar comunidad; ese patrón corresponde a Valentina / Juan. Andrés / Laura ya tiene un negocio funcionando. Su problema principal es que la operación, la atención y las ventas dependen demasiado de su tiempo y memoria."},{"type":"list","label":"Hipótesis que debemos validar","items":["Que el tamaño más representativo es de dos a cinco personas, aunque puede incluir negocios unipersonales o ligeramente mayores.","Que la dependencia del propietario es el patrón común más útil para segmentar, por encima del sector.","Que ventas, atención y seguimiento constituyen el problema de entrada más transversal.","Que WhatsApp es el principal espacio operativo y de conversión para una parte importante del segmento.","Que Instagram es el canal de descubrimiento más eficiente para bienestar, turismo, cultura, gastronomía y comercio local.","Que Google y Google Maps son relevantes cuando el cliente ya busca una solución específica.","Que los casos por sector generan más confianza que los contenidos generales sobre IA.","Que prefiere una conversación diagnóstica breve a formularios o procesos comerciales extensos.","Que el presupuesto es sensible al retorno y valora empezar con una solución pequeña y escalable.","Que el mantenimiento, soporte y acompañamiento reducen el temor a que la solución quede abandonada.","Que la formación funciona mejor incluida en la implementación que como promesa inicial.","Que la privacidad y el manejo de datos son barreras decisivas en salud, bienestar y servicios sensibles.","Que puede avanzar desde una solución de ventas hacia operación, analítica y desarrollos personalizados.","Que \"emprendedor operador\" es un nombre reconocible o debe sustituirse por una expresión más cercana para comunicación pública."]},{"type":"text","label":"Conclusión estratégica","body":"Andrés / Laura no deberían aparecer principalmente dentro de la línea Escuela Divergente. Deben ubicarse en la línea Productos Divergente, como compradores de sistemas. Divergente no le enseña primero a construir el sistema. Le ayuda a identificarlo, implementarlo y utilizarlo para que su pequeña empresa funcione mejor. Promesa final: \"Haz que tu negocio funcione mejor con inteligencia artificial y automatización, sin convertirte en técnico ni llenar tu empresa de herramientas.\""}]}]}'::jsonb
  where slug = 'laura';
